const esc = (value = '') => String(value).replace(/[&<>"']/g, (char) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[char]));

const card = (title, body, meta = '') => `<article class="card"><h3>${esc(title)}</h3><p>${body}</p>${meta ? `<div class="meta">${meta}</div>` : ''}</article>`;
const statement = (number, body) => `<div class="numbered"><div class="n">${String(number).padStart(2, '0')}</div><div>${body}</div></div>`;
const list = (items) => `<ul class="clean-list">${items.map((item) => `<li>${item}</li>`).join('')}</ul>`;
const chips = (items) => `<div class="chips">${items.map((item) => `<span>${item}</span>`).join('')}</div>`;
const source = (slides, label, classes, body, note) => ({ slides, label, classes, body, note });

